type Category = "length" | "weight" | "temperature" | "volume" | "speed";

const CONVERSIONS: Record<Category, { units: string[]; toBase: (v: number, u: string) => number; fromBase: (v: number, u: string) => number }> = {
  length: {
    units: ["meter", "kilometer", "centimeter", "millimeter", "inch", "foot", "yard", "mile"],
    toBase: (v, u) => ({ meter: 1, kilometer: 1000, centimeter: 0.01, millimeter: 0.001, inch: 0.0254, foot: 0.3048, yard: 0.9144, mile: 1609.344 }[u] ?? 1) * v,
    fromBase: (v, u) => v / (({ meter: 1, kilometer: 1000, centimeter: 0.01, millimeter: 0.001, inch: 0.0254, foot: 0.3048, yard: 0.9144, mile: 1609.344 }[u] ?? 1)),
  },
  weight: {
    units: ["kilogram", "gram", "milligram", "pound", "ounce", "ton"],
    toBase: (v, u) => ({ kilogram: 1, gram: 0.001, milligram: 0.000001, pound: 0.453592, ounce: 0.0283495, ton: 1000 }[u] ?? 1) * v,
    fromBase: (v, u) => v / (({ kilogram: 1, gram: 0.001, milligram: 0.000001, pound: 0.453592, ounce: 0.0283495, ton: 1000 }[u] ?? 1)),
  },
  temperature: {
    units: ["celsius", "fahrenheit", "kelvin"],
    toBase: (v, u) => u === "celsius" ? v : u === "fahrenheit" ? (v - 32) * 5 / 9 : v - 273.15,
    fromBase: (v, u) => u === "celsius" ? v : u === "fahrenheit" ? v * 9 / 5 + 32 : v + 273.15,
  },
  volume: {
    units: ["liter", "milliliter", "gallon (US)", "quart", "pint", "cup", "fluid oz"],
    toBase: (v, u) => ({ "liter": 1, "milliliter": 0.001, "gallon (US)": 3.78541, "quart": 0.946353, "pint": 0.473176, "cup": 0.236588, "fluid oz": 0.0295735 }[u] ?? 1) * v,
    fromBase: (v, u) => v / (({ "liter": 1, "milliliter": 0.001, "gallon (US)": 3.78541, "quart": 0.946353, "pint": 0.473176, "cup": 0.236588, "fluid oz": 0.0295735 }[u] ?? 1)),
  },
  speed: {
    units: ["m/s", "km/h", "mph", "knot", "ft/s"],
    toBase: (v, u) => ({ "m/s": 1, "km/h": 1 / 3.6, "mph": 0.44704, "knot": 0.514444, "ft/s": 0.3048 }[u] ?? 1) * v,
    fromBase: (v, u) => v / (({ "m/s": 1, "km/h": 1 / 3.6, "mph": 0.44704, "knot": 0.514444, "ft/s": 0.3048 }[u] ?? 1)),
  },
};

const CATEGORIES = Object.keys(CONVERSIONS) as Category[];

